(function(){'use strict';const qs=(s,r=document)=>r.querySelector(s);const qsa=(s,r=document)=>Array.from(r.querySelectorAll(s));const reduced=window.matchMedia('(prefers-reduced-motion: reduce)').matches;function setLocked(v){document.body.classList.toggle('menu-locked',v)}function initRailPanels(root=document){qsa('[data-rail-item]',root).forEach(btn=>{const panelRoot=btn.closest('.mega-panel')||btn.closest('.mobile-drawer')||document;const key=btn.dataset.railItem;function activate(){qsa('[data-rail-item]',panelRoot).forEach(b=>b.classList.toggle('is-active',b===btn));qsa('[data-rail-content]',panelRoot).forEach(p=>{const on=p.dataset.railContent===key;p.classList.toggle('is-active',on);p.toggleAttribute('hidden',!on);});}btn.addEventListener('mouseenter',activate);btn.addEventListener('focus',activate);});}function initHeaderMenu(){const triggers=qsa('[data-menu-item]');const panels=qsa('[data-menu-dropdown]');const backdrop=qs('[data-menu-backdrop]');if(!triggers.length||!panels.length)return;let active=null;function close(){active=null;triggers.forEach(t=>t.setAttribute('aria-expanded','false'));panels.forEach(p=>{p.hidden=true;p.setAttribute('aria-hidden','true')});if(backdrop)backdrop.hidden=true;setLocked(false)}function open(key){active=key;triggers.forEach(t=>t.setAttribute('aria-expanded',String(t.dataset.menuItem===key)));panels.forEach(p=>{const on=p.dataset.menuDropdown===key;p.hidden=!on;p.setAttribute('aria-hidden',String(!on));});if(backdrop)backdrop.hidden=false;setLocked(true)}triggers.forEach(t=>t.addEventListener('click',e=>{e.stopPropagation();active===t.dataset.menuItem?close():open(t.dataset.menuItem)}));document.addEventListener('click',e=>{if(active&&!e.target.closest('.site-header'))close()});document.addEventListener('keydown',e=>{if(e.key==='Escape')close()});if(backdrop)backdrop.addEventListener('click',close);initRailPanels();}function initMobileDrawer(){const open=qs('[data-mobile-open]');const drawer=qs('[data-mobile-drawer]');const close=qs('[data-mobile-close]');const backdrop=qs('[data-menu-backdrop]');if(!open||!drawer)return;function show(){drawer.hidden=false;open.setAttribute('aria-expanded','true');if(backdrop)backdrop.hidden=false;setLocked(true)}function hide(){drawer.hidden=true;open.setAttribute('aria-expanded','false');if(backdrop&&!qsa('[data-menu-dropdown]').some(p=>!p.hidden))backdrop.hidden=true;setLocked(false)}open.addEventListener('click',show);if(close)close.addEventListener('click',hide);if(backdrop)backdrop.addEventListener('click',hide);document.addEventListener('keydown',e=>{if(e.key==='Escape')hide()});qsa('[data-accordion-trigger]',drawer).forEach(btn=>{const panel=qs('#'+btn.getAttribute('aria-controls'),drawer);if(!panel)return;btn.addEventListener('click',()=>{const expanded=btn.getAttribute('aria-expanded')==='true';btn.setAttribute('aria-expanded',String(!expanded));panel.hidden=expanded;});});}function initPortfolioFilter(){const wrap=qs('[data-filter-wrap]');if(!wrap)return;const buttons=qsa('[data-filter]',wrap);const cards=qsa('[data-category]');buttons.forEach(btn=>btn.addEventListener('click',()=>{const filter=btn.dataset.filter;buttons.forEach(b=>b.classList.toggle('is-active',b===btn));cards.forEach(card=>{card.hidden=filter!=='all'&&card.dataset.category!==filter;});}));}function initCarousel(){const car=qs('[data-carousel]');if(!car)return;const slides=qsa('[data-slide]',car);if(slides.length<2||reduced)return;let i=0;setInterval(()=>{slides[i].hidden=true;i=(i+1)%slides.length;slides[i].hidden=false;},5200);}function initBeforeAfter(){qsa('[data-before-after]').forEach(box=>{const range=qs('input[type="range"]',box);const after=qs('[data-after]',box);if(!range||!after)return;range.addEventListener('input',()=>after.style.clipPath='inset(0 '+(100-range.value)+'% 0 0)');});}function initTestimonials(){qsa('[data-testimonial-tabs]').forEach(wrap=>{const tabs=qsa('[data-testimonial]',wrap);tabs.forEach(tab=>tab.addEventListener('click',()=>{tabs.forEach(t=>t.classList.toggle('is-active',t===tab));}));});}function initScrollReveal(){if(reduced||!('IntersectionObserver'in window))return;const items=qsa('.card,.case-card,.resource-card,.metric,.visual-card');items.forEach(i=>i.style.opacity='.001');const io=new IntersectionObserver(entries=>entries.forEach(entry=>{if(entry.isIntersecting){entry.target.style.transition='opacity .45s ease, transform .45s ease';entry.target.style.opacity='1';entry.target.style.transform='translateY(0)';io.unobserve(entry.target);}}),{threshold:.12});items.forEach(i=>{i.style.transform='translateY(18px)';io.observe(i);});}window.initHeaderMenu=initHeaderMenu;window.initMobileDrawer=initMobileDrawer;window.initRailPanels=initRailPanels;window.initPortfolioFilter=initPortfolioFilter;window.initCarousel=initCarousel;window.initBeforeAfter=initBeforeAfter;window.initTestimonials=initTestimonials;window.initScrollReveal=initScrollReveal;document.addEventListener('DOMContentLoaded',()=>{initHeaderMenu();initMobileDrawer();initRailPanels();initPortfolioFilter();initCarousel();initBeforeAfter();initTestimonials();initScrollReveal();});})();